package com.vidaysalud.veterinaria.consultaservicio.controller;import com.vidaysalud.veterinaria.consultaservicio.dto.*;import com.vidaysalud.veterinaria.consultaservicio.service.ConsultaService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.LocalDateTime;import java.util.*;@RestController @RequestMapping("/api/v1/consultas") @RequiredArgsConstructor public class ConsultaController{private final ConsultaService s;@GetMapping public ResponseEntity<ApiResponse<List<ConsultaResponseDTO>>>l(){return ok("Consultas obtenidas",s.listar());}@GetMapping("/{id}")public ResponseEntity<ApiResponse<ConsultaResponseDTO>>b(@PathVariable Integer id){return ok("Consulta encontrada",s.buscar(id));}@GetMapping("/mascota/{id}")public ResponseEntity<ApiResponse<List<ConsultaResponseDTO>>>m(@PathVariable Integer id){return ok("Historial de mascota",s.mascota(id));}@PostMapping public ResponseEntity<ApiResponse<ConsultaResponseDTO>>c(@Valid @RequestBody ConsultaRequestDTO d){return ResponseEntity.status(201).body(resp(HttpStatus.CREATED,"Consulta creada",s.crear(d)));}@PutMapping("/{id}")public ResponseEntity<ApiResponse<ConsultaResponseDTO>>u(@PathVariable Integer id,@Valid @RequestBody ConsultaRequestDTO d){return ok("Consulta actualizada",s.actualizar(id,d));}@DeleteMapping("/{id}")public ResponseEntity<ApiResponse<Void>>d(@PathVariable Integer id){s.eliminar(id);return ok("Consulta eliminada",null);}private<T>ResponseEntity<ApiResponse<T>>ok(String m,T d){return ResponseEntity.ok(resp(HttpStatus.OK,m,d));}private<T>ApiResponse<T>resp(HttpStatus h,String m,T d){return ApiResponse.<T>builder().timestamp(LocalDateTime.now()).status(h.value()).mensaje(m).data(d).build();}}